+// BeadsStatus is the resolver for the beadsStatus field.
+func (r *queryResolver) BeadsStatus(ctx context.Context) (*BeadStatusCounts, error) {
+	if r.workingDir(ctx) == "" {
+		return nil, fmt.Errorf("working directory not configured")
+	}
+	store := bead.NewStore(filepath.Join(r.workingDir(ctx), ".ddx"))
+	counts, err := store.Status()
+	if err != nil {
+		return nil, err
+	}
+	nhBeads, err := store.List("open", "needs_human", nil)
+	if err != nil {
+		return nil, err
+	}
+	wBeads, err := store.ReadyExecution()
+	if err != nil {
+		return nil, err
+	}
+	return &BeadStatusCounts{
+		Open:        counts.Open,
+		Closed:      counts.Closed,
+		Blocked:     counts.Blocked,
+		Ready:       counts.Ready,
+		Total:       counts.Total,
+		NeedsHuman:  len(nhBeads),
+		WorkerReady: len(wBeads),
+	}, nil
+}

